#include <stdio.h>

char a[105];

int main(){
	int n;
	int i;
	scanf("%d",&n);
	scanf("%s",a);

	for(i=0; i<n-1; i++){
		if(a[i] == a[i+1] && a[i] != '?'){
			printf("No\n");
			return 0;
		}
	}

	for(i=0; i<n; i++){
		if(a[i] == '?'){
			if(i==0 || i==n-1){
				printf("Yes\n");
				return 0;
			}
			else if(a[i-1] == '?' || a[i+1] == '?'){
				printf("Yes\n");
				return 0;
			}
			else if(a[i-1] == a[i+1]){
				printf("Yes\n");
				return 0;
			}
		}
	}

	printf("No\n");
	return 0;
}

