use std::io;

#[derive(Debug, Copy, Clone, PartialEq)]
enum Color {
    C,
    Y,
    M,
    U,
}

impl Color {
    fn create(c: char) -> Self {
        match c {
            'C' => Color::C,
            'Y' => Color::Y,
            'M' => Color::M,
            _ => Color::U,
        }
    }
}

